import { useState } from 'react';
import {
    Typography, TextField, Button, CircularProgress,
} from '@mui/material';
import VpnKeyIcon from '@mui/icons-material/VpnKey';
import { AuthServices } from '@/api/auth.api';
import { CallStatus } from '@/types/api.types';
import { PageCard } from '@/components/PageCard';
import { PageContainer } from '@/components/PageContainer';
import { StatusMessage } from '@/components/StatusMessage';
import { FormContainer } from '@/components/ui/FormContainer';
import { submitButtonStyle } from '@/constants/ThemeConstants';
import { getApiError } from '@/utils/apiError';

export function AdminOtp() {
    const [email, setEmail] = useState('');
    const [otp, setOtp] = useState('');
    const [generatedOtp, setGeneratedOtp] = useState('');
    const [status, setStatus] = useState<CallStatus>(CallStatus.NotStarted);
    const [errorMsg, setErrorMsg] = useState('');

    const handleGenerate = async () => {
        if (!email.trim() || !otp.trim()) return;
        setStatus(CallStatus.InProgress);
        setErrorMsg('');
        setGeneratedOtp('');
        try {
            const res = await AuthServices.AdminGenerateOtp({ email: email.trim(), otp: otp.trim() });
            if (res.data?.status === 200 && res.data.result) {
                setGeneratedOtp(res.data.result);
                setStatus(CallStatus.Success);
            } else {
                setErrorMsg(getErrorMessage(res.data?.status ?? 0));
                setStatus(CallStatus.Failure);
            }
        } catch (err) {
            setErrorMsg(getErrorMessage(getApiError(err).httpStatus));
            setStatus(CallStatus.Failure);
        }
    };

    return (
        <PageContainer
            icon={<VpnKeyIcon color="primary" />}
            title="Generate OTP"
            subtitle="SuperAdmin: issue an OTP for any user."
        >
            <PageCard>
                <FormContainer>
                    <TextField
                        label="User Email"
                        type="email"
                        value={email}
                        onChange={e => setEmail(e.target.value)}
                        disabled={status === CallStatus.InProgress}
                    />
                    <TextField
                        label="Your OTP (verification)"
                        value={otp}
                        onChange={e => setOtp(e.target.value)}
                        disabled={status === CallStatus.InProgress}
                    />
                    <Button
                        variant="contained"
                        style={submitButtonStyle}
                        onClick={handleGenerate}
                        disabled={!email.trim() || !otp.trim() || status === CallStatus.InProgress}
                    >
                        {status === CallStatus.InProgress ? <CircularProgress size={20} /> : 'Generate'}
                    </Button>
                </FormContainer>
            </PageCard>

            <StatusMessage
                currentStatus={status}
                failureMessage={errorMsg}
            />

            {status === CallStatus.Success && generatedOtp && (
                <PageCard>
                    <Typography variant="body2" sx={{ color: 'text.secondary', mb: 1 }}>
                        OTP for {email}
                    </Typography>
                    <Typography variant="h4" sx={{ fontWeight: 700, color: 'text.primary', letterSpacing: 4 }}>
                        {generatedOtp}
                    </Typography>
                </PageCard>
            )}
        </PageContainer>
    );
}

function getErrorMessage(status: number): string {
    switch (status) {
        case 0: return 'Network error. Please check your internet connection.';
        case 400: return 'Invalid request. Please verify your OTP and email.';
        case 401: return 'Unauthorized. Please login again.';
        case 403: return 'Access denied. SuperAdmin role required.';
        case 404: return 'User not found with the given email.';
        case 429: return 'Too many requests. Please wait a moment.';
        case 500: return 'Server error. Please try again later.';
        default: return 'Failed to generate OTP. Please try again.';
    }
}
